  const caseTF    = buildTF(tokenize((caseObj.fatos || '') + ' ' + (caseObj.pedido_autor || '') + ' ' + (caseObj.pedido_autor || '')));
  const simScore  = cosineSimilarity(queryTF, caseTF);
