const TEMPERATURE   = parseFloat(readEnv('CLAUDE_TEMPERATURE', '0.12')) || 0.12;
const TIMEOUT_MS    = Math.max(10000, parseInt(readEnv('CLAUDE_TIMEOUT_MS', '120000'), 10) || 45000);

// ── SYSTEM PROMPT (Fase 2 — expandido com few-shot, padrao de qualidade, antipadroes) ──
// Fica no bloco `system` com cache_control ephemeral — apos a 1a chamada,
// o custo de tokens extras e amortizado via prompt-caching da Anthropic.

// Montar bloco de exemplares few-shot dinamicamente
let fewShotBlock = '';
const fewShots = Array.isArray(exemplares_fewshot) ? exemplares_fewshot : [];
if (fewShots.length > 0) {
  fewShotBlock = '\n\n== EXEMPLOS DE TESES BEM-SUCEDIDAS (curadoria do escritório) ==\n' +
    fewShots.map((ex, i) => [
      `Exemplo ${i+1} — ${ex.tipo_acao}:`,
      `  Tese central: ${ex.tese_central}`,
      `  Fundamentos-chave: ${ex.fundamentos_resumo.slice(0, 800)}`
    ].join('\n')).join('\n\n') +
    '\n(Use como referência de estilo e estrutura — nunca copie ipsis litteris.)';
}

const SYSTEM_PROMPT = `Voce e um agente juridico especialista em contestacoes civeis no Brasil, integrado ao sistema AutoJuri.

SUA TAREFA: Redigir minuta de contestacao para revisao humana.

== PADRAO DE QUALIDADE (obrigatorio) ==
- Linguagem formal juridica: use terminologia tecnica correta (reclamante/reclamado, autor/reu, vara, turma, acorda, etc.).
- Cite legislacao de forma generica quando pertinente (ex: "nos termos do art. 14 do CDC", "conforme art. 818 da CLT") — NUNCA invente numero de acórdao, REsp, processo ou sumula inexistente.
- Estrutura obrigatoria: I — Preliminares (se houver), II — Do Merito, III — Pedidos.
- Seja objetivo: evite superlativos ("eminentissimo", "nobilissima"), frases de efeito vazias e repeticoes.
- Priorize os pontos listados em pontos_usuario acima dos demais argumentos.
- Se MODELO_MAE existir, preserve estilo, estrutura e marcadores de formatacao.

== ANTIPADROES (evite sempre) ==
- Inventar numeros de jurisprudencia, artigos ou sumas que nao existem.
- Tese central generica demais: "o pedido e improcedente" sem fundamento especifico.
- Linguagem informal ou coloquial.
- Repetir os fatos do autor sem contraposicao juridica.
- Afirmacoes sobre o merito sem base no caso concreto informado.
- Citar leis sem indicar como se aplicam ao caso.
${fewShotBlock}

== REGRAS DE CONTEXTO ==
- Se DEFESAS_ANTERIORES_SIMILARES existirem, use como referencia de tese e estrategia (nunca copie ipsis litteris).
- Se TEXTO_PETICAO_BASE existir, identifique pontos centrais e responda tecnicamente ponto a ponto.

Responda SOMENTE JSON valido (sem markdown, sem codeblock) com exatamente estas chaves:
{
  "resumo_estrategico": "...",
  "tese_central": "...",
  "pontos_atendidos": ["..."],
  "sintese": "...",
  "fundamentos": "...",
  "pedidos": "...",
  "observacoes": "...",
  "riscos": ["..."]
}`;

// ── montar contexto das defesas anteriores (com fundamentos_curtos — Fase 2) ─
let defesasCtx = '';
const casos = defesas_anteriores?.casos || [];
if (casos.length > 0) {
  defesasCtx = '\n\nDEFESAS_ANTERIORES_SIMILARES (mesmo tipo_acao, rankeadas por relevancia + feedback):\n' +
    casos.map((c, i) => [
      `Caso ${i+1}: ${c.numero_processo} (${c.tipo_acao})`,
      `  Fatos resumo: ${c.fatos_resumo}`,
      `  Pedido autor: ${c.pedido_autor_resumo}`,
      `  Tese central usada: ${c.tese_central}`,
      `  Estrategia: ${c.resumo_estrategico}`,
      // Fase 2: incluir fundamentos curtos das defesas bem-sucedidas
      c.fundamentos_curtos ? `  Fundamentos-chave: ${c.fundamentos_curtos}` : '',
      `  Riscos: ${(c.riscos || []).join('; ')}`
    ].filter(Boolean).join('\n')).join('\n\n');
}

// ── montar mensagem do usuario ───────────────────────────────────────────────
const casoJson = JSON.stringify({
  numero_processo:       contexto.numero_processo,
  autor:                 contexto.autor,
  reu:                   contexto.reu,
  tipo_acao:             contexto.tipo_acao,
  fatos:                 contexto.fatos,
  pedido_autor:          contexto.pedido_autor,
  pontos_usuario:        contexto.pontos_usuario,
  texto_editado_ao_vivo: contexto.texto_editado_ao_vivo || '',
  texto_peticao_base:    contexto.arquivo_base?.conteudo_texto || '',
  modelo_mae_texto:      contexto.modelo_mae_texto || ''
}, null, 2);

const USER_MSG = `CASO_JSON:\n${casoJson}${defesasCtx}`;

// ── fallback local ───────────────────────────────────────────────────────────
function buildFallback(motivo) {
  const c = contexto;
  const pontosStr = (c.pontos_usuario || []).map((p, i) => `  ${i+1}. ${p}`).join('\n') || '  (nenhum ponto especificado)';
  const tesesAnteriores = casos.length > 0 ? `\n\nDefesas anteriores similares indicam tese: ${casos[0].tese_central}` : '';
  return {
    resumo_estrategico: `Contestacao ao processo ${c.numero_processo} (${c.tipo_acao}). Estrategia: improcedencia dos pedidos autorais.`,
    tese_central: 'Improcedencia dos pedidos autorais por ausencia de fundamento legal e factual.' + tesesAnteriores,
    pontos_atendidos: c.pontos_usuario || [],
    sintese: `Trata-se de contestacao referente ao processo ${c.numero_processo}, proposta por ${c.autor} em face de ${c.reu}, versando sobre ${c.tipo_acao}.`,
    fundamentos: `I — DO MERITO\n\nFatos narrados: ${c.fatos.slice(0, 800)}\n\nPontos do contestante:\n${pontosStr}\n\nNao ha embasamento juridico para o pedido formulado.`,
    pedidos: `Ante o exposto, requer:\n(i) O recebimento da presente contestacao;\n(ii) A improcedencia de todos os pedidos do autor;\n(iii) Honorarios advocaticios;\n(iv) Producao de provas.`,
    observacoes: `Minuta em modo fallback local (motivo: ${motivo}). Revise antes de protocolar.`,
    riscos: ['Revisar prazos processuais', 'Verificar jurisprudencia atual', 'Confirmar documentos']
  };
}

// ── chamar API Claude ────────────────────────────────────────────────────────
let minutaRaw = null;
let provider  = 'fallback_local';
let apiError  = null;

if (!ANTHROPIC_KEY) {
  apiError = 'ANTHROPIC_API_KEY nao configurada';
} else {
  try {
    const resp = await callClaudeWithRetry(`${BASE_URL}/v1/messages`, {
      method: 'POST',
      headers: {
        'x-api-key':        ANTHROPIC_KEY,
        'anthropic-version': API_VERSION,
        'content-type':     'application/json',
        'anthropic-beta':   'prompt-caching-2024-07-31'
      },
      body: JSON.stringify({
        model:       CLAUDE_MODEL,
        max_tokens:  MAX_TOKENS,
        temperature: TEMPERATURE,
        system: [{ type: 'text', text: SYSTEM_PROMPT, cache_control: { type: 'ephemeral' } }],
        messages: [{ role: 'user', content: USER_MSG }]
      })
    });
    if (!resp.ok) { const e = await resp.text().catch(() => ''); throw new Error(`HTTP ${resp.status}: ${e.slice(0, 200)}`); }
    const payload = await resp.json();
    // PR9 P3.1 — extrai tokens da resposta para observabilidade de custo
    if (payload && payload.usage) {
      tokens_input = parseInt(payload.usage.input_tokens, 10) || 0;
      tokens_output = parseInt(payload.usage.output_tokens, 10) || 0;
    }
    minutaRaw = (payload.content || []).filter(b => b.type === 'text').map(b => b.text).join('').trim();
    if (!minutaRaw) throw new Error('resposta_ia_sem_conteudo');
    provider = 'claude';
  } catch (e) {
    apiError = e.__TIMED_OUT === true ? `timeout_${TIMEOUT_MS}ms` : e.message;
  } finally {
    }
}

// ── parsear resposta ─────────────────────────────────────────────────────────
let minuta;
if (provider === 'claude' && minutaRaw) {
  try { minuta = JSON.parse(stripFences(minutaRaw)); }
  catch (e) { apiError = `json_parse_error: ${e.message}`; provider = 'fallback_local'; }
}
if (!minuta) minuta = buildFallback(apiError || 'sem_chave');

// ── limitar tamanhos ─────────────────────────────────────────────────────────
const clipStr = (v, max) => typeof v === 'string' && v.length > max ? v.slice(0, max) + '…' : (v || '');
minuta.resumo_estrategico = clipStr(minuta.resumo_estrategico, 3000);
minuta.tese_central       = clipStr(minuta.tese_central, 2000);
minuta.sintese            = clipStr(minuta.sintese, 10000);
minuta.fundamentos        = clipStr(minuta.fundamentos, 15000);
minuta.pedidos            = clipStr(minuta.pedidos, 8000);
minuta.observacoes        = clipStr(minuta.observacoes, 6000);
minuta.pontos_atendidos   = Array.isArray(minuta.pontos_atendidos) ? minuta.pontos_atendidos.slice(0, 12) : [];
minuta.riscos             = Array.isArray(minuta.riscos) ? minuta.riscos.slice(0, 6) : [];

return [{
  json: {
    status: 'agente_processado',
    contexto, recebido_em, defesas_anteriores,
    engine_ia: {
      provider,
      model:        provider === 'claude' ? CLAUDE_MODEL : 'deterministico',
      endpoint:     provider === 'claude' ? `${BASE_URL}/v1/messages` : null,
      temperature:  TEMPERATURE,
      max_tokens:   MAX_TOKENS,
      api_error:    apiError || null,
      tokens_input,
      tokens_output,
      tokens_total: tokens_input + tokens_output,
      custo_estimado_usd: tokens_input || tokens_output ? parseFloat(((tokens_input/1000000*3) + (tokens_output/1000000*15)).toFixed(6)) : 0,
      fewshot_count: fewShots.length,
      rag_count:    casos.length
    },
    minuta
  }
}];
